import{_ as o,c as e,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"쿼터 거버넌스: Quota Protection 및 워밍업 | Antigravity-Manager","description":"Antigravity-Manager 쿼터 거버넌스 메커니즘을 학습합니다. Quota Protection으로 임계값별 모델 보호, Smart Warmup 자동 워밍업, 정기 스캔 및 쿨링 제어를 지원합니다.","frontmatter":{"title":"쿼터 거버넌스: Quota Protection 및 워밍업 | Antigravity-Manager","subtitle":"쿼터 거버넌스: Quota Protection 및 워밍업 | Antigravity-Manager","sidebarTitle":"모델 쿼터 보호하기","description":"Antigravity-Manager 쿼터 거버넌스 메커니즘을 학습합니다. Quota Protection으로 임계값별 모델 보호, Smart Warmup 자동 워밍업, 정기 스캔 및 쿨링 제어를 지원합니다.","tags":["quota","warmup","accounts","proxy"],"prerequisite":["start-add-account","start-proxy-and-first-client"],"order":5},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/advanced/quota/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/advanced/quota/index.md"}'),d={name:"ko/lbjlaq/Antigravity-Manager/advanced/quota/index.md"};function c(n,t,i,l,s,u){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="쿼터-거버넌스-quota-protection-smart-warmup의-조합-전술" tabindex="-1">쿼터 거버넌스: Quota Protection + Smart Warmup의 조합 전술 <a class="header-anchor" href="#쿼터-거버넌스-quota-protection-smart-warmup의-조합-전술" aria-label="Permalink to &quot;쿼터 거버넌스: Quota Protection + Smart Warmup의 조합 전술&quot;">​</a></h1><p>Antigravity Tools로 프록시를 실행하는 것은 꽤 안정적이지만, 가장 두려운 것은 한 가지입니다: 주력 모델의 쿼터가 &quot;몰래 다 먹혀&quot;, 진짜 사용할 때才发现이 이미 너무 낮아서 호출할 수 없는 것입니다.</p><p>이 수업은 <strong>쿼터 거버넌스</strong>만 전문으로 설명합니다: Quota Protection을 사용하여 핵심 모델을 확보하고, Smart Warmup을 사용하여 쿼터가 다시 차면 &quot;가벼운 워밍업&quot;을 한 번 수행하여, 임시 실패를 줄입니다.</p><h2 id="쿼터-거버넌스란-무엇인가요" tabindex="-1">쿼터 거버넌스란 무엇인가요? <a class="header-anchor" href="#쿼터-거버넌스란-무엇인가요" aria-label="Permalink to &quot;쿼터 거버넌스란 무엇인가요?&quot;">​</a></h2><p><strong>쿼터 거버넌스</strong>는 Antigravity Tools에서 두 세트 연동 메커니즘을 사용하여 &quot;쿼터를 어떻게 쓸 것인가&quot;를 제어하는 것을 말합니다: 어떤 모델의 남은 쿼터가 임계값 아래로 떨어지면, Quota Protection은 해당 모델을 계정의 <code>protected_models</code>에 넣고, 해당 모델을 요청할 때 우선적으로 회피합니다. 쿼터가 100%로 돌아오면, Smart Warmup은 극히 작은 트래픽으로 한 번 워밍업 요청을 트리거하고, 로컬 역사 파일로 4시간 쿨링을 수행합니다.</p><h2 id="이-수업을-마치면-할-수-있는-것" tabindex="-1">이 수업을 마치면 할 수 있는 것 <a class="header-anchor" href="#이-수업을-마치면-할-수-있는-것" aria-label="Permalink to &quot;이 수업을 마치면 할 수 있는 것&quot;">​</a></h2><ul><li>Quota Protection을 활성화하여, 낮은 쿼터 계정이 자동으로 &quot;비켜가게&quot; 하고, 고가치 모델을 핵심 요청에 남겨둘 수 있습니다</li><li>Smart Warmup을 활성화하여, 쿼터가 다시 차면 자동으로 워밍업하고(4시간 쿨링이 트리거 주파수에 어떻게 영향을 주는지 알 수 있습니다), 4시간 쿨링이 트리거 주파수에 어떻게 영향을 주는지 알 수 있습니다</li><li><code>quota_protection</code> / <code>scheduled_warmup</code> / <code>protected_models</code> 세 필드가 각각 어디서 작동하는지 명확히 할 수 있습니다</li><li>어떤 모델 이름이 &quot;보호 그룹&quot;으로 정규화되는지(어떤 것은 아님) 알 수 있습니다</li></ul><h2 id="현재의-문제점" tabindex="-1">현재의 문제점 <a class="header-anchor" href="#현재의-문제점" aria-label="Permalink to &quot;현재의 문제점&quot;">​</a></h2><ul><li>&quot;계정 로테이션&quot;을 한다고 생각하지만, 실제로는 계속 동일한 종류의 고가치 모델을 소비하고 있습니다</li><li>쿼터가 낮아서才发现이고, 심지어 Claude Code/클라이언트가 백그라운드에서 warmup하여 할당량을 갉아먹을 수도 있습니다</li><li>워밍업을 켰지만, 정확히 언제 트리거되는지, 쿨링이 있는지, 쿼터에 영향을 주는지 모릅니다</li></ul><h2 id="언제-이-방법을-사용해야-할까요" tabindex="-1">언제 이 방법을 사용해야 할까요? <a class="header-anchor" href="#언제-이-방법을-사용해야-할까요" aria-label="Permalink to &quot;언제 이 방법을 사용해야 할까요?&quot;">​</a></h2><ul><li>여러 계정 풀이 있고, 핵심 모델이 &quot;중요한 순간&quot;에 여전히 남아 있기를 원합니다</li><li>쿼터가 다시 차는 시간을 수동으로 계속 보고 싶지 않고, 시스템이 자동으로 &quot;다 찼을 때의 가벼운 검증&quot;을 하게 하고 싶습니다</li></ul><h2 id="🎒-시작-전-준비" tabindex="-1">🎒 시작 전 준비 <a class="header-anchor" href="#🎒-시작-전-준비" aria-label="Permalink to &quot;🎒 시작 전 준비&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">전제 조건</p><p>이 수업은 기본적으로 다음을 할 수 있다고 가정합니다:</p><ul><li><strong>Accounts</strong> 페이지에서 계정 목록을 보고, 쿼터를 수동으로 새로고침할 수 있습니다</li><li>이미 로컬 리버스 프록시를 시작했고(최소 <code>/healthz</code>에 접근 가능)</li></ul><p>아직 실행하지 않았다면, 먼저 **<a href="/docs/opencodedocs/ko/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">로컬 리버스 프록시 시작 및 첫 번째 클라이언트 연결</a>**를 보세요.</p></div><p>또한, Smart Warmup은 로컬 역사 파일 <code>warmup_history.json</code>을 씁니다. 이것은 데이터 디렉터리에 있으며, 데이터 디렉터리 위치와 백업 방법은 먼저 **<a href="/docs/opencodedocs/ko/lbjlaq/Antigravity-Manager/start/first-run-data/">최초 실행 필독: 데이터 디렉터리, 로그, 트레이 및 자동 시작</a>**을 보세요.</p><h2 id="핵심-아이디어" tabindex="-1">핵심 아이디어 <a class="header-anchor" href="#핵심-아이디어" aria-label="Permalink to &quot;핵심 아이디어&quot;">​</a></h2><p>이 &quot;조합 전술&quot;은 실제로 매우 간단합니다:</p><ul><li>Quota Protection은 &quot;더 이상 낭비하지 마세요&quot;를 담당합니다: 어떤 모델이 임계값 아래로 떨어지면, 보호 모델로 표시하고, 해당 모델을 요청할 때 우선적으로 회피합니다(모델 레벨, 계정을 일괄 금지하지 않음).</li><li>Smart Warmup은 &quot;다 찼으면 한 번 검증하세요&quot;를 담당합니다: 모델이 100%로 돌아오면, 가벼운 요청을 한 번 트리거하여 링크가 사용 가능한지 확인하고, 4시간 쿨링으로 반복 방해를 피합니다.</li></ul><p>이들은 모두 프론트엔드의 <code>AppConfig</code>에 있는 구성 필드에 해당합니다:</p><ul><li><code>quota_protection.enabled / threshold_percentage / monitored_models</code>(<code>src/types/config.ts</code> 참조)</li><li><code>scheduled_warmup.enabled / monitored_models</code>(<code>src/types/config.ts</code> 참조)</li></ul><p>그리고 실제로 &quot;해당 모델을 요청할 때 이 계정을 건너뛸지 결정하는&quot; 논리는 백엔드 TokenManager에 있습니다:</p><ul><li>계정 파일의 <code>protected_models</code>는 <code>get_token(..., target_model)</code>에서 필터링에 참여합니다(<code>src-tauri/src/proxy/token_manager.rs</code> 참조)</li><li><code>target_model</code>은 먼저 한 번 정규화(<code>normalize_to_standard_id</code>)하므로, <code>claude-sonnet-4-5-thinking</code> 같은 변형은 동일한 &quot;보호 그룹&quot;으로 접힙니다(<code>src-tauri/src/proxy/common/model_mapping.rs</code> 참조)</li></ul><h2 id="다음-수업-예고" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><blockquote><p>다음 수업에서는 **<a href="/docs/opencodedocs/ko/lbjlaq/Antigravity-Manager/advanced/monitoring/">Proxy Monitor: 요청 로그, 필터링, 상세 복원 및 내보내기</a>**를 학습하여, 호출 블랙박스를 복습 가능한 증거 체인으로 만듭니다.</p></blockquote><h2 id="따라해-보세요" tabindex="-1">따라해 보세요 <a class="header-anchor" href="#따라해-보세요" aria-label="Permalink to &quot;따라해 보세요&quot;">​</a></h2><h3 id="_1단계-먼저-쿼터를-숫자가-있게-새로고침" tabindex="-1">1단계: 먼저 쿼터를 &quot;숫자가 있게&quot; 새로고침 <a class="header-anchor" href="#_1단계-먼저-쿼터를-숫자가-있게-새로고침" aria-label="Permalink to &quot;1단계: 먼저 쿼터를 &quot;숫자가 있게&quot; 새로고침&quot;">​</a></h3><p><strong>왜 필요한가요?</strong> Quota Protection은 계정의 <code>quota.models[].percentage</code>를 기준으로 판단합니다. 쿼터가 새로고침되지 않았으면, 보호 논리가 당신에게 아무것도 할 수 없습니다.</p><p>작업 경로: <strong>Accounts</strong> 페이지를 열고, 도구 모음의 새로고침 버튼을 클릭합니다(단일 계정 또는 전체 가능).</p><p><strong>보아야 할 것</strong>: 계정 행에 각 모델의 쿼터 퍼센트(예: 0-100)와 reset time이 나타납니다.</p><h3 id="_2단계-settings에서-smart-warmup-열기-선택사항이지만-추천" tabindex="-1">2단계: Settings에서 Smart Warmup 열기(선택사항이지만 추천) <a class="header-anchor" href="#_2단계-settings에서-smart-warmup-열기-선택사항이지만-추천" aria-label="Permalink to &quot;2단계: Settings에서 Smart Warmup 열기(선택사항이지만 추천)&quot;">​</a></h3><p><strong>왜 필요한가요?</strong> Smart Warmup의 목표는 &quot;쿼터 절약&quot;이 아니라 &quot;쿼터가 다 찼을 때 한 번 링크 자체 검증&quot;입니다. 이것은 모델 쿼터가 100%일 때만 트리거되며, 4시간 쿨링이 있습니다.</p><p>작업 경로: <strong>Settings</strong>에 들어가서, 계정 관련 설정 영역으로 전환하고, <strong>Smart Warmup</strong> 스위치를 켜고, 모니터링할 모델을 체크합니다.</p><p>설정 저장을 잊지 마세요.</p><p><strong>보아야 할 것</strong>: Smart Warmup이 펼쳐지고 모델 목록이 나타납니다. 최소 1개 모델이 체크되어 있어야 합니다.</p><h3 id="_3단계-quota-protection-열기-및-임계값과-모니터링-모델-설정" tabindex="-1">3단계: Quota Protection 열기 및 임계값과 모니터링 모델 설정 <a class="header-anchor" href="#_3단계-quota-protection-열기-및-임계값과-모니터링-모델-설정" aria-label="Permalink to &quot;3단계: Quota Protection 열기 및 임계값과 모니터링 모델 설정&quot;">​</a></h3><p><strong>왜 필요한가요?</strong> Quota Protection은 &quot;여유 남기기&quot;의 핵심입니다: 모니터링 모델의 쿼터 퍼센트 <code>&lt;= threshold_percentage</code>일 때, 해당 모델을 계정 파일의 <code>protected_models</code>에 쓰고, 이후 해당 모델을 요청할 때 이러한 계정을 우선적으로 회피합니다.</p><p>작업 경로: <strong>Settings</strong>에서 <strong>Quota Protection</strong>을 엽니다.</p><ol><li>임계값 설정(<code>1-99</code>)</li><li>모니터링할 모델 체크(최소 1개)</li></ol><div class="tip custom-block"><p class="custom-block-title">매우 좋은 기본 구성</p><p>너무 고민하지 않으려면, 기본 <code>threshold_percentage=10</code>부터 시작하면 됩니다(<code>src/pages/Settings.tsx</code> 참조).</p></div><p><strong>보아야 할 것</strong>: Quota Protection의 모델 체크가 최소 1개 유지됩니다(UI가 마지막 하나도 취소하는 것을 방지합니다).</p><h3 id="_4단계-보호-그룹-정규화-가-함정에-빠지게-하지-않는지-확인" tabindex="-1">4단계: &quot;보호 그룹 정규화&quot;가 함정에 빠지게 하지 않는지 확인 <a class="header-anchor" href="#_4단계-보호-그룹-정규화-가-함정에-빠지게-하지-않는지-확인" aria-label="Permalink to &quot;4단계: &quot;보호 그룹 정규화&quot;가 함정에 빠지게 하지 않는지 확인&quot;">​</a></h3><p><strong>왜 필요한가요?</strong> TokenManager는 쿼터 보호 판단을 할 때, 먼저 <code>target_model</code>을 표준 ID(<code>normalize_to_standard_id</code>)로 정규화합니다. 예를 들어 <code>claude-sonnet-4-5-thinking</code>은 <code>claude-sonnet-4-5</code>로 정규화됩니다.</p><p>이것은 의미합니다:</p><ul><li>Quota Protection에서 <code>claude-sonnet-4-5</code>를 체크합니다</li><li>실제로 <code>claude-sonnet-4-5-thinking</code>을 요청합니다</li></ul><p>여전히 보호에 적중합니다(왜냐하면 이들은 동일한 그룹에 속하기 때문입니다).</p><p><strong>보아야 할 것</strong>: 어떤 계정의 <code>protected_models</code>에 <code>claude-sonnet-4-5</code>가 포함될 때, <code>claude-sonnet-4-5-thinking</code>에 대한 요청은 해당 계정을 우선적으로 회피합니다.</p><h3 id="_5단계-즉시-검증이-필요할-때-수동-워밍업-으로-한-번-warmup-트리거" tabindex="-1">5단계: 즉시 검증이 필요할 때, &quot;수동 워밍업&quot;으로 한 번 warmup 트리거 <a class="header-anchor" href="#_5단계-즉시-검증이-필요할-때-수동-워밍업-으로-한-번-warmup-트리거" aria-label="Permalink to &quot;5단계: 즉시 검증이 필요할 때, &quot;수동 워밍업&quot;으로 한 번 warmup 트리거&quot;">​</a></h3><p><strong>왜 필요한가요?</strong> 정기 Smart Warmup의 스캔 주기는 10분에 한 번입니다(<code>src-tauri/src/modules/scheduler.rs</code> 참조). 즉시 링크를 검증하고 싶으면, 수동 워밍업이 더 직접적입니다.</p><p>작업 경로: <strong>Accounts</strong> 페이지를 열고, 도구 모음의 &quot;워밍업&quot; 버튼을 클릭합니다:</p><ul><li>계정을 선택하지 않음: 전량 워밍업 트리거(<code>warm_up_all_accounts</code> 호출)</li><li>계정 선택: 선택한 계정에 대해 각각 워밍업 트리거(<code>warm_up_account</code> 호출)</li></ul><p><strong>보아야 할 것</strong>: toast가 나타나고, 내용은 백엔드가 반환한 문자열에서 옵니다(예: &quot;Warmup task triggered ...&quot;).</p><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><ul><li>Accounts 페이지에서 각 계정의 모델 쿼터 퍼센트를 볼 수 있습니다(쿼터 데이터 체인 OK 증명)</li><li>Settings에서 Quota Protection / Smart Warmup을 열고, 구성을 성공적으로 저장할 수 있습니다</li><li><code>protected_models</code>는 &quot;모델 레벨&quot; 제한임을 이해합니다: 한 계정은 특정 모델에 대해서만 회피될 수 있습니다</li><li>warmup에 4시간 쿨링이 있다는 것을 알고 있습니다: 짧은 시간 내에 반복해서 워밍업을 클릭하면, &quot;skipped/cooldown&quot; 관련 프롬프트를 볼 수 있습니다</li></ul><h2 id="일반적인-실수" tabindex="-1">일반적인 실수 <a class="header-anchor" href="#일반적인-실수" aria-label="Permalink to &quot;일반적인 실수&quot;">​</a></h2><h3 id="_1-quota-protection을-켰지만-계속-적용되지-않음" tabindex="-1">1) Quota Protection을 켰지만 계속 적용되지 않음 <a class="header-anchor" href="#_1-quota-protection을-켰지만-계속-적용되지-않음" aria-label="Permalink to &quot;1) Quota Protection을 켰지만 계속 적용되지 않음&quot;">​</a></h3><p>가장 일반적인 원인은: 계정에 <code>quota</code> 데이터가 없습니다. 보호 논리는 백엔드에서 먼저 <code>quota.models[]</code>를 읽어야만 임계값을 판단할 수 있습니다(<code>src-tauri/src/proxy/token_manager.rs</code> 참조).</p><p><strong>1단계</strong>로 돌아가서, 먼저 쿼터를 새로고침하세요.</p><h3 id="_2-왜-소수의-모델만-보호-그룹-으로-간주되는가요" tabindex="-1">2) 왜 소수의 모델만 &quot;보호 그룹&quot;으로 간주되는가요? <a class="header-anchor" href="#_2-왜-소수의-모델만-보호-그룹-으로-간주되는가요" aria-label="Permalink to &quot;2) 왜 소수의 모델만 &quot;보호 그룹&quot;으로 간주되는가요?&quot;">​</a></h3><p>TokenManager의 <code>target_model</code> 정규화는 &quot;화이트리스트식&quot;입니다: 명확하게 나열된 모델 이름만 표준 ID로 매핑됩니다(<code>src-tauri/src/proxy/common/model_mapping.rs</code> 참조).</p><p>정규화 후의 논리는: 정규화된 이름(표준 ID 또는 원래 모델 이름)으로 계정의 <code>protected_models</code> 필드를 일치시킵니다. 일치에 성공하면, 해당 계정은 건너뜁니다(<code>src-tauri/src/proxy/token_manager.rs:555-560, 716-719</code> 참조). 이것은 의미합니다:</p><ul><li>화이트리스트 내의 모델(예: <code>claude-sonnet-4-5-thinking</code>)은 표준 ID(<code>claude-sonnet-4-5</code>)로 정규화되고, 다음 <code>protected_models</code>에 있는지 판단합니다</li><li>화이트리스트 외의 모델은 정규화 실패 시 원래 모델 이름으로 돌아가고, 여전히 <code>protected_models</code>를 일치시킵니다</li></ul><p>즉, 쿼터 보호 판단은 &quot;모든 모델 이름&quot;에 대해 유효하며, 화이트리스트 내의 모델은 먼저 정규화될 뿐입니다.</p><h3 id="_3-수동-정기-워밍업은-왜-프록시가-실행-중이어야-하는가요" tabindex="-1">3) 수동/정기 워밍업은 왜 프록시가 실행 중이어야 하는가요? <a class="header-anchor" href="#_3-수동-정기-워밍업은-왜-프록시가-실행-중이어야-하는가요" aria-label="Permalink to &quot;3) 수동/정기 워밍업은 왜 프록시가 실행 중이어야 하는가요?&quot;">​</a></h3><p>워밍업 요청은 최종적으로 로컬 프록시의 내부 엔드포인트에 닿습니다: <code>POST /internal/warmup</code>(<code>src-tauri/src/proxy/server.rs</code>의 라우트 및 <code>src-tauri/src/proxy/handlers/warmup.rs</code>의 구현 참조). 프록시 서비스를 시작하지 않으면, warmup은 실패합니다.</p><p>또한, 워밍업 호출하는 포트는 구성에서 옵니다: <code>proxy.port</code>(구성 읽기 실패 시 <code>8045</code>로 롤백, <code>src-tauri/src/modules/quota.rs</code> 참조).</p><h2 id="이-수업-요약" tabindex="-1">이 수업 요약 <a class="header-anchor" href="#이-수업-요약" aria-label="Permalink to &quot;이 수업 요약&quot;">​</a></h2><ul><li>Quota Protection은 &quot;손실 멈추기&quot;를 담당합니다: 임계값 아래에서 모델을 <code>protected_models</code>에 넣고, 해당 모델을 요청할 때 우선적으로 회피합니다</li><li>Smart Warmup은 &quot;다 찼으면 자체 검증&quot;을 담당합니다. 100%에서만 트리거하고, 10분에 한 번 스캔하고, 4시간 쿨링합니다</li><li>두 가지는 모두 &quot;쿼터 새로고침&quot; 체인에 의존합니다: 먼저 <code>quota.models[]</code>가 있어야, 거버넌스에 기반이 있습니다</li></ul><h2 id="다음-수업-예고-1" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고-1" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><p>쿼터 거버넌스는 &quot;더 안정적으로 쓰기&quot;를 해결합니다. 다음 수업에서는 Proxy Monitor를 계속 보아, 요청 로그, 계정 적중, 모델 매핑을 모두 복습 가능한 증거 체인으로 만드는 것을 추천합니다.</p><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 확인</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>라인</th></tr></thead><tbody><tr><td>Quota Protection UI(임계값, 모델 체크, 최소 1개 유지)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/QuotaProtection.tsx#L13-L168" target="_blank" rel="noreferrer"><code>src/components/settings/QuotaProtection.tsx</code></a></td><td>13-168</td></tr><tr><td>Smart Warmup UI(활성화 후 기본 체크, 최소 1개 유지)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/SmartWarmup.tsx#L14-L120" target="_blank" rel="noreferrer"><code>src/components/settings/SmartWarmup.tsx</code></a></td><td>14-120</td></tr><tr><td>쿼터 거버넌스 구성 필드(<code>quota_protection</code> / <code>scheduled_warmup</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/types/config.ts#L54-L94" target="_blank" rel="noreferrer"><code>src/types/config.ts</code></a></td><td>54-94</td></tr><tr><td>기본 임계값 및 기본 구성(<code>threshold_percentage: 10</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L20-L51" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>20-51</td></tr><tr><td><code>protected_models</code> 쓰기/복원(임계값 판단 및 디스크 저장)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L254-L467" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>254-467</td></tr><tr><td>요청 측 쿼터 보호 필터링(<code>get_token(..., target_model)</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L470-L674" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>470-674</td></tr><tr><td>보호 그룹 정규화(<code>normalize_to_standard_id</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L230-L254" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>230-254</td></tr><tr><td>Smart Warmup 정기 스캔(10분마다 한 번 + 4시간 쿨링 + <code>warmup_history.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L11-L221" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>11-221</td></tr><tr><td>수동 워밍업 명령(<code>warm_up_all_accounts</code> / <code>warm_up_account</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L167-L212" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>167-212</td></tr><tr><td>워밍업 구현(내부 엔드포인트 <code>/internal/warmup</code> 호출)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/quota.rs#L271-L512" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/quota.rs</code></a></td><td>271-512</td></tr><tr><td>내부 워밍업 엔드포인트 구현(요청 구성 + 업스트림 호출)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/warmup.rs#L3-L220" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/warmup.rs</code></a></td><td>3-220</td></tr></tbody></table></details>',71)])])}const h=o(d,[["render",c]]);export{m as __pageData,h as default};
